#include <vector>
#include <string>
#include <algorithm>
#include <regex>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> validCodes;
    vector<pair<string, string>> categorized; // businessLine, code

    // Define valid business lines in order
    vector<string> validBusinessLines = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Regex for valid code: only alphanumeric and underscore
    regex codePattern("^[a-zA-Z0-9_]+$");

    for (size_t i = 0; i < code.size(); ++i) {
        // Check all conditions
        if (!code[i].empty() && 
            regex_match(code[i], codePattern) && 
            find(validBusinessLines.begin(), validBusinessLines.end(), businessLine[i]) != validBusinessLines.end() && 
            isActive[i]) {
            categorized.emplace_back(businessLine[i], code[i]);
        }
    }

    // Custom comparator
    auto comparator = [&validBusinessLines](const pair<string, string>& a, const pair<string, string>& b) {
        auto aPos = find(validBusinessLines.begin(), validBusinessLines.end(), a.first);
        auto bPos = find(validBusinessLines.begin(), validBusinessLines.end(), b.first);
        if (aPos != bPos) {
            return aPos < bPos;
        } else {
            return a.second < b.second;
        }
    };

    // Sort the categorized coupons
    sort(categorized.begin(), categorized.end(), comparator);

    // Extract the codes in order
    for (const auto& entry : categorized) {
        validCodes.push_back(entry.second);
    }

    return validCodes;
}

